  ('s-h2-105', 'course-mandarin-1', '这是北方。', 'Zhè shì běi fāng.', 'This is north.', 2, null),
  ('s-h2-106', 'course-mandarin-1', '这是比如说。', 'Zhè shì bǐ rú shuō.', 'This is for example.', 2, null),
  ('s-h2-107', 'course-mandarin-1', '这是笔记本。', 'Zhè shì bǐ jì běn.', 'This is notebook (stationery).', 2, null),
