  ('s-h2-109', 'course-mandarin-1', '这是遍。', 'Zhè shì biàn.', 'This is variant of 遍.', 2, null),
  ('s-h2-110', 'course-mandarin-1', '这是不但。', 'Zhè shì bù dàn.', 'This is not only (... but also ...).', 2, null),
  ('s-h2-111', 'course-mandarin-1', '这是不好意思。', 'Zhè shì bù hǎo yì si.', 'This is to feel embarrassed.', 2, null),
  ('s-h2-112', 'course-mandarin-1', '这是不如。', 'Zhè shì bù rú.', 'This is not equal to.', 2, null),
  ('s-h2-113', 'course-mandarin-1', '这是不同。', 'Zhè shì bù tóng.', 'This is different.', 2, null),
  ('s-h2-114', 'course-mandarin-1', '这是不一定。', 'Zhè shì bù yī dìng.', 'This is not necessarily.', 2, null),
  ('s-h2-115', 'course-mandarin-1', '这是才。', 'Zhè shì cái.', 'This is ability; talent.', 2, null),
  ('s-h2-116', 'course-mandarin-1', '这是参加。', 'Zhè shì cān jiā.', 'This is to participate.', 2, null),
  ('s-h2-117', 'course-mandarin-1', '这是层。', 'Zhè shì céng.', 'This is to pile on top of one another.', 2, null),
  ('s-h2-118', 'course-mandarin-1', '这是常见。', 'Zhè shì cháng jiàn.', 'This is commonly seen.', 2, null),
  ('s-h2-119', 'course-mandarin-1', '这是超过。', 'Zhè shì chāo guò.', 'This is to surpass.', 2, null),
  ('s-h2-120', 'course-mandarin-1', '这是称。', 'Zhè shì chèn.', 'This is to fit.', 2, null),
  ('s-h2-121', 'course-mandarin-1', '这是成为。', 'Zhè shì chéng wéi.', 'This is to become; to turn into.', 2, null),
  ('s-h2-122', 'course-mandarin-1', '这是出口。', 'Zhè shì chū kǒu.', 'This is an exit.', 2, null),
  ('s-h2-123', 'course-mandarin-1', '这是出现。', 'Zhè shì chū xiàn.', 'This is to appear.', 2, null),
  ('s-h2-124', 'course-mandarin-1', '这是春节。', 'Zhè shì Chūn jié.', 'This is Spring Festival (Chinese New Year).', 2, null),
  ('s-h2-125', 'course-mandarin-1', '这是词典。', 'Zhè shì cí diǎn.', 'This is dictionary.', 2, null),
  ('s-h2-126', 'course-mandarin-1', '这是答应。', 'Zhè shì dā ying.', 'This is to answer; to respond.', 2, null),
  ('s-h2-127', 'course-mandarin-1', '这是打印。', 'Zhè shì dǎ yìn.', 'This is to affix a seal.', 2, null),
  ('s-h2-128', 'course-mandarin-1', '这是大多数。', 'Zhè shì dà duō shù.', 'This is (great) majority.', 2, null),
  ('s-h2-129', 'course-mandarin-1', '这是大量。', 'Zhè shì dà liàng.', 'This is great amount.', 2, null),
