  ('lesson-h2-dla-p1-1-ex-1', 'lesson-h2-dla-p1-1', 'listening', 'Listen and select the meaning', '{"hanzi":"安静","options":["quiet","interjection of surprise","north","office"],"correctAnswer":"quiet","pinyin":"ān jìng"}'::jsonb, 'You heard: 安静 (ān jìng)', 1),
  ('lesson-h2-dla-p1-1-ex-2', 'lesson-h2-dla-p1-1', 'listening', 'Listen and select the meaning', '{"hanzi":"班长","options":["notebook (stationery)","interjection of surprise","class monitor","office"],"correctAnswer":"class monitor","pinyin":"bān zhǎng"}'::jsonb, 'You heard: 班长 (bān zhǎng)', 2),
